    /// Drains the static notification queue to prevent cross-test contamination.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        var svc = new ContosoUniversity.Services.NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }
}

