+using ContosoUniversity.Data;
+using Microsoft.EntityFrameworkCore;
+
+namespace ContosoUniversity.Tests;
+
+public class PaginatedListTests
+{
+    [Fact]
+    public void Constructor_SetsProperties()
+    {
+        // Arrange
+        var items = new List<string> { "a", "b", "c" };
+
+        // Act
+        var list = new PaginatedList<string>(items, 10, 2, 3);
+
+        // Assert
+        Assert.Equal(2, list.PageIndex);
+        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
+        Assert.Equal(3, list.Count);
+        Assert.Equal("a", list[0]);
+    }
+
+    [Fact]
+    public void HasPreviousPage_FirstPage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
+        Assert.False(list.HasPreviousPage);
+    }
+
+    [Fact]
+    public void HasPreviousPage_SecondPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
+        Assert.True(list.HasPreviousPage);
+    }
+
+    [Fact]
+    public void HasNextPage_LastPage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3); // TotalPages=2
+        Assert.False(list.HasNextPage);
+    }
+
+    [Fact]
+    public void HasNextPage_NotLastPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3); // TotalPages=2
+        Assert.True(list.HasNextPage);
+    }
+
+    [Theory]
+    [InlineData(10, 3, 4)]
+    [InlineData(9, 3, 3)]
+    [InlineData(1, 3, 1)]
+    [InlineData(0, 3, 0)]
+    public void TotalPages_CalculatesCorrectly(int count, int pageSize, int expectedPages)
+    {
+        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+        Assert.Equal(expectedPages, list.TotalPages);
+    }
+
+    [Fact]
+    public void Create_ReturnsCorrectPage()
+    {
+        // Arrange - use InMemory EF context to get IQueryable
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(Guid.NewGuid().ToString())
+            .Options;
+        using var context = new SchoolContext(options);
+
+        // Add students
+        for (int i = 0; i < 25; i++)
+        {
+            context.Students.Add(new ContosoUniversity.Models.Student
+            {
+                FirstMidName = $"First{i}",
+                LastName = $"Last{i}",
+                EnrollmentDate = DateTime.Today
+            });
+        }
+        context.SaveChanges();
+
+        // Act
+        var result = PaginatedList<ContosoUniversity.Models.Student>.Create(
+            context.Students.OrderBy(s => s.LastName), 2, 10);
+
+        // Assert
+        Assert.Equal(2, result.PageIndex);
+        Assert.Equal(3, result.TotalPages); // ceil(25/10) = 3
+        Assert.Equal(10, result.Count);
+        Assert.True(result.HasPreviousPage);
+        Assert.True(result.HasNextPage);
+    }
+
+    [Fact]
+    public void Create_LastPage_HasCorrectItemCount()
+    {
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(Guid.NewGuid().ToString())
+            .Options;
+        using var context = new SchoolContext(options);
+
+        for (int i = 0; i < 25; i++)
+        {
+            context.Students.Add(new ContosoUniversity.Models.Student
+            {
+                FirstMidName = $"First{i}",
+                LastName = $"Last{i}",
+                EnrollmentDate = DateTime.Today
+            });
+        }
+        context.SaveChanges();
+
+        var result = PaginatedList<ContosoUniversity.Models.Student>.Create(
+            context.Students.OrderBy(s => s.LastName), 3, 10);
+
+        Assert.Equal(3, result.PageIndex);
+        Assert.Equal(5, result.Count); // 25 - 20 = 5 on last page
+        Assert.True(result.HasPreviousPage);
+        Assert.False(result.HasNextPage);
+    }
+}
+

