using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // ---- Index ----

    [Fact]
    public void Index_NoParams_ReturnsViewWithStudents()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count); // 3 seeded students
    }

    [Fact]
    public void Index_SearchString_FiltersStudents()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Alonso", model[0].LastName);
    }

    [Fact]
    public void Index_SortByNameDesc_SortsCorrectly()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.True(model.Count > 1);
        // name_desc sorts by LastName descending
        Assert.True(string.Compare(model[0].LastName, model[1].LastName, StringComparison.Ordinal) >= 0);
    }

    [Fact]
    public void Index_SortByDate_SortsCorrectly()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.True(model.Count > 1);
        Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_SortByDateDesc_SortsCorrectly()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.True(model.Count > 1);
        Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_DefaultSort_SortsByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
        Assert.True(model.Count >= 2);
        Assert.True(string.Compare(model[0].LastName, model[1].LastName, StringComparison.Ordinal) <= 0);
    }

    [Fact]
    public void Index_SearchStringNotNull_ResetsPageTo1()
    {
        var result = _controller.Index(null, null, "A", 5) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        var result = _controller.Index("Date", null, "test", null) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal("Date", _controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        Assert.Equal("", _controller.ViewBag.NameSortParm); // non-empty sortOrder -> ""
        Assert.Equal("test", _controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
    {
        _controller.Index(null, null, null, null);
        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
    }

    // ---- Details ----

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Details(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
        Assert.Equal(student.LastName, model.LastName);
    }

    // ---- Create (GET) ----

    [Fact]
    public void Create_Get_ReturnsViewWithStudent()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // ---- Create (POST) ----

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "User",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Contains(_context.Students, s => s.LastName == "User");
    }

    [Fact]
    public void Create_Post_MinDateEnrollment_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "",
            EnrollmentDate = DateTime.Today
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.Equal(student, result.Model);
    }

    // ---- Edit (GET) ----

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Edit(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(99999);
        Assert.IsType<NotFoundResult>(result);
    }

    // ---- Edit (POST) ----

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.AsNoTracking().First();
        student.FirstMidName = "Updated";

        var result = _controller.Edit(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_MinDateEnrollment_AddsModelError()
    {
        var student = _context.Students.AsNoTracking().First();
        student.EnrollmentDate = DateTime.MinValue;

        var result = _controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = _context.Students.AsNoTracking().First();

        var result = _controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
    }

    // ---- Delete (GET) ----

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsStudent()
    {
        var student = _context.Students.First();
        var result = _controller.Delete(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(99999);
        Assert.IsType<NotFoundResult>(result);
    }

    // ---- DeleteConfirmed (POST) ----

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesAndRedirects()
    {
        var student = _context.Students.First();
        int id = student.ID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Students.Find(id));
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;
    private readonly string _tempDir;

    public CoursesControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateSeededContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _tempDir = Path.Combine(Path.GetTempPath(), "contoso_tests_" + Guid.NewGuid());
        Directory.CreateDirectory(_tempDir);
        _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
        if (Directory.Exists(_tempDir))
        {
            try { Directory.Delete(_tempDir, true); } catch { }
        }
    }

    // ---- Index ----

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    // ---- Details ----

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsCourse()
    {
        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Course>(result.Model);
        Assert.Equal(1050, model.CourseID);
        Assert.Equal("Chemistry", model.Title);
    }

    // ---- Create (GET) ----

    [Fact]
    public void Create_Get_ReturnsViewWithDepartments()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        var model = Assert.IsType<Course>(result.Model);
    }

    // ---- Create (POST) ----

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.NotNull(_context.Courses.Find(9999));
    }

    [Fact]
    public void Create_Post_ValidCourse_WithImage_UploadsAndRedirects()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Image Course",
            Credits = 3,
            DepartmentID = 1
