namespace ContosoUniversity.Tests;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    [Fact]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        var result = _controller.GetNotifications();

        Assert.NotNull(result);
        var data = result.Value as dynamic;
        Assert.NotNull(data);
    }

    [Fact]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - send notifications via the controller's notificationService (via BaseController)
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        // Verify we got the notifications by checking the JSON value
        var jsonValue = result.Value;
        Assert.NotNull(jsonValue);

        // Access properties using reflection since it's an anonymous type
        var successProp = jsonValue.GetType().GetProperty("success");
        Assert.NotNull(successProp);
        Assert.True((bool)successProp.GetValue(jsonValue)!);

        var countProp = jsonValue.GetType().GetProperty("count");
        Assert.NotNull(countProp);
        Assert.Equal(2, (int)countProp.GetValue(jsonValue)!);
    }

    [Fact]
    public void GetNotifications_LimitsTo10()
    {
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Type", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var jsonValue = result.Value;
        Assert.NotNull(jsonValue);
        var countProp = jsonValue!.GetType().GetProperty("count");
        Assert.Equal(10, (int)countProp!.GetValue(jsonValue)!);
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.NotNull(result);
        var jsonValue = result.Value;
        Assert.NotNull(jsonValue);
        var successProp = jsonValue!.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(jsonValue)!);
    }
