+
+        Assert.Contains(context.Students, s => s.LastName == "Alexander" && s.FirstMidName == "Carson");
+        Assert.Contains(context.Students, s => s.LastName == "Olivetto" && s.FirstMidName == "Nino");
+    }
+
+    [Fact]
+    public void Initialize_SeedsSpecificDepartments()
+    {
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(Guid.NewGuid().ToString())
+            .Options;
+
+        using var context = new SchoolContext(options);
