+
+        Assert.Contains(context.Departments, d => d.Name == "English");
+        Assert.Contains(context.Departments, d => d.Name == "Mathematics");
+        Assert.Contains(context.Departments, d => d.Name == "Engineering");
+        Assert.Contains(context.Departments, d => d.Name == "Economics");
+    }
+
+    [Fact]
+    public void Initialize_SeedsCoursesWithCorrectIDs()
+    {
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(Guid.NewGuid().ToString())
+            .Options;
+
+        using var context = new SchoolContext(options);
+        DbInitializer.Initialize(context);
+
+        Assert.NotNull(context.Courses.Find(1050)); // Chemistry
+        Assert.NotNull(context.Courses.Find(4022)); // Microeconomics
+        Assert.NotNull(context.Courses.Find(1045)); // Calculus
+    }
+
+    [Fact]
+    public void Initialize_SeedsOfficeAssignments()
+    {
+        var options = new DbContextOptionsBuilder<SchoolContext>()
+            .UseInMemoryDatabase(Guid.NewGuid().ToString())
+            .Options;
+
+        using var context = new SchoolContext(options);
+        DbInitializer.Initialize(context);
+
+        var offices = context.OfficeAssignments.ToList();
+        Assert.Contains(offices, o => o.Location == "Smith 17");
