+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.EntityFrameworkCore;
+
+namespace ContosoUniversity.Tests;
+
+/// <summary>
+/// Tests for BaseController's SendEntityNotification and Dispose methods
+/// via a concrete controller subclass.
+/// </summary>
+public class BaseControllerTests : IDisposable
+{
+    private readonly SchoolContext _context;
+
+    public BaseControllerTests()
+    {
+        TestHelpers.DrainNotificationQueue();
+        _context = TestHelpers.CreateContext();
+    }
+
+    public void Dispose()
+    {
+        _context.Dispose();
+        TestHelpers.DrainNotificationQueue();
+    }
+
+    [Fact]
+    public void SendEntityNotification_TwoOverloadVersion_EnqueuesNotification()
+    {
+        // Use StudentsController which inherits from BaseController
+        using var controller = new StudentsController(_context);
+
+        // Create a student to trigger notification via Create
+        var student = new Student
+        {
+            FirstMidName = "Test",
+            LastName = "Notify",
+            EnrollmentDate = DateTime.Parse("2023-01-01")
+        };
+
+        controller.Create(student);
+
+        // Verify notification was sent
+        var svc = new ContosoUniversity.Services.NotificationService();
+        var notification = svc.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Student", notification.EntityType);
+        Assert.Contains("Notify", notification.Message);
+    }
+
+    [Fact]
+    public void Dispose_DisposesContextAndNotificationService()
+    {
+        var controller = new HomeController(_context);
+
+        // Should not throw
+        var ex = Record.Exception(() => controller.Dispose());
+        Assert.Null(ex);
+    }
+
+    [Fact]
+    public void SendEntityNotification_WithoutDisplayName_UsesIdInMessage()
+    {
+        using var context = TestHelpers.CreateSeededContext();
+        using var controller = new InstructorsController(context);
+
+        var instructor = new Instructor
+        {
+            FirstMidName = "Test",
+            LastName = "NotifyNoName",
+            HireDate = DateTime.Parse("2020-01-01"),
+            CourseAssignments = new List<CourseAssignment>()
+        };
+
+        controller.Create(instructor, null!);
+
+        var svc = new ContosoUniversity.Services.NotificationService();
+        var notification = svc.ReceiveNotification();
+        Assert.NotNull(notification);
+        Assert.Equal("Instructor", notification.EntityType);
+        // InstructorsController uses the 3-param overload (no display name)
+        Assert.Contains("Instructor (ID:", notification.Message);
+    }
+}
